public class CustomBlockEntity extends BlockEntity {
    private int customData = 0;
    public CustomBlockEntity(BlockPos pos, BlockState state) {
        super(ModBlockEntities.CUSTOM, pos, state);
    }
    public int getCustomData() { return customData; }
    public void setCustomData(int data) { this.customData = data; markDirty(); }
    @Override
    public void writeNbt(NbtCompound nbt) { super.writeNbt(nbt); nbt.putInt("custom_data", customData); }
    @Override
    public void readNbt(NbtCompound nbt) { super.readNbt(nbt); this.customData = nbt.getInt("custom_data"); }
}

public class ModBlockEntities {
    public static final BlockEntityType<CustomBlockEntity> CUSTOM = Registry.register(Registries.BLOCK_ENTITY_TYPE, new Identifier("modid", "custom"), FabricBlockEntityTypeBuilder.create(CustomBlockEntity::new, ModBlocks.CUSTOM_BLOCK).build());
    public static void register() {}
}

public class CustomBlockWithEntity extends Block implements BlockEntityProvider {
    public CustomBlockWithEntity(Settings settings) { super(settings); }
    @Override
    public BlockEntity createBlockEntity(BlockPos pos, BlockState state) { return new CustomBlockEntity(pos, state); }
    @Override
    public BlockRenderType getRenderType(BlockState state) { return BlockRenderType.MODEL; }
}

