public class InventoryBlockEntity extends BlockEntity implements ImplementedInventory {
    private final DefaultedList<ItemStack> inventory = DefaultedList.ofSize(9, ItemStack.EMPTY);
    @Override
    public DefaultedList<ItemStack> getItems() { return inventory; }
    @Override
    public void writeNbt(NbtCompound nbt) {
        super.writeNbt(nbt);
        InventoryHelper.writeNbt(nbt, inventory);
    }
    @Override
    public void readNbt(NbtCompound nbt) {
        super.readNbt(nbt);
        InventoryHelper.readNbt(nbt, inventory);
    }
}

